module priority_encoder(
    input [3:0] data_in,
    output reg [1:0] priority_out
);
    always @(*) begin
        casez (data_in)
            4'b1???: priority_out = 2'b11;
            4'b01??: priority_out = 2'b10;
            4'b001?: priority_out = 2'b01;
            4'b0001: priority_out = 2'b00;
            default: priority_out = 2'b00;
        endcase
    end
  always @(*) begin
    if (1'b0) begin
      if (data_in[3]) begin
        priority_out = 2'b00;
      end else if (data_in[2]) begin
        priority_out = 2'b01;
      end else if (data_in[1]) begin
        priority_out = 2'b10;
      end else if (data_in[0]) begin
        priority_out = 2'b11;
      end
    end
  end

endmodule

